// CF15 WF_REVENUE_ATTRIBUTION — normalize, scope to published topics needing attribution.
// Triggers:
//   - Schedule (1st of month, 04:00 UTC): scope = all published topics (revenue_attributed_at null or stale)
//   - Webhook POST /webhook/revenue/attribute: { project_id?, topic_id?, force? }
// Output: one item per topic-batch-of-10. Global fetch + $env.

const raw = $input.first().json;
const viaWebhook = !!raw.body;
const payload = raw.body || {};
const projectIdFilter = payload.project_id || null;
const topicIdFilter = payload.topic_id || null;
const force = payload.force === true;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// First of current month — UTC, YYYY-MM-01
const now = new Date();
const snapshotMonth = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1)).toISOString().slice(0, 10);
const firstOfMonthIso = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1)).toISOString();

// 30-day window
const windowEnd = new Date(now); // today
const windowStart = new Date(now.getTime() - 30 * 86400000);
const startDate = windowStart.toISOString().slice(0, 10);
const endDate = windowEnd.toISOString().slice(0, 10);

// Build scope query — published topics with youtube_video_id.
// If !force: only topics with revenue_attributed_at IS NULL OR < first of this month.
let scopeUrl = `${supabaseUrl}/rest/v1/topics?youtube_video_id=not.is.null&status=eq.published&select=id,project_id,youtube_video_id,published_at,revenue_attributed_at&limit=500&order=published_at.desc.nullslast`;
if (topicIdFilter) {
  scopeUrl = `${supabaseUrl}/rest/v1/topics?id=eq.${topicIdFilter}&select=id,project_id,youtube_video_id,published_at,revenue_attributed_at`;
} else {
  if (projectIdFilter) scopeUrl += `&project_id=eq.${projectIdFilter}`;
  if (!force) scopeUrl += `&or=(revenue_attributed_at.is.null,revenue_attributed_at.lt.${encodeURIComponent(firstOfMonthIso)})`;
}

const res = await fetch(scopeUrl, { method: 'GET', headers: sbHeaders });
if (!res.ok) {
  throw new Error(`Scope topics failed: HTTP ${res.status}: ${await res.text()}`);
}
const topics = await res.json();

if (!topics || topics.length === 0) {
  return [{
    json: {
      skipped: true,
      reason: 'No topics need revenue attribution',
      via_webhook: viaWebhook,
      snapshot_month: snapshotMonth,
      http_status: 200
    }
  }];
}

// Batch 10 topics per item for stable Claude-free iteration
const BATCH = 10;
const items = [];
for (let i = 0; i < topics.length; i += BATCH) {
  items.push({
    json: {
      topics: topics.slice(i, i + BATCH),
      snapshot_month: snapshotMonth,
      start_date: startDate,
      end_date: endDate,
      via_webhook: viaWebhook,
      force,
      batch_index: Math.floor(i / BATCH)
    }
  });
}
return items;

// Per batch: for each topic:
//   1. Sum production cost from production_logs, group by stage
//   2. Pull YouTube Analytics (views/impressions/CTR/AVD/revenue + traffic sources) last 30d
//   3. Compute RPM, ROI, break-even
//   4. UPSERT revenue_attribution
//   5. PATCH topics with snapshot columns
//   6. Backfill pps_calibration actuals for any rows predicting this topic
// Graceful fallback if YOUTUBE_OAUTH_TOKEN missing. Inline backoff for external calls.

const data = $input.item.json;
if (data.skipped) return $input.item;

const topics = data.topics || [];
if (topics.length === 0) return { json: { ...data, processed: 0 } };

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const ytOauth = $env.YOUTUBE_OAUTH_TOKEN;
const ytChannelId = $env.YOUTUBE_CHANNEL_ID;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

async function fetchWithRetry(url, options, label, maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      if (res.ok) return { ok: true, json: await res.json(), attempts: attempt };
      const body = await res.text();
      if (res.status >= 400 && res.status < 500 && res.status !== 429) {
        return { ok: false, status: res.status, error: body, attempts: attempt };
      }
      lastErr = new Error(`HTTP ${res.status}: ${body.slice(0, 300)}`);
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, error: lastErr?.message || `${label} failed`, attempts: maxRetries };
}

// Cache RPM benchmark per niche_rpm_category (lookup only what's needed)
const rpmCache = new Map();
async function getRpmMid(project) {
  const category = project.niche_rpm_category;
  if (!category) return null;
  if (rpmCache.has(category)) return rpmCache.get(category);
  try {
    const res = await fetch(`${supabaseUrl}/rest/v1/rpm_benchmarks?category=eq.${encodeURIComponent(category)}&select=rpm_mid&limit=1`, { method: 'GET', headers: sbHeaders });
    if (res.ok) {
      const rows = await res.json();
      const rpmMid = rows && rows[0] ? Number(rows[0].rpm_mid) : null;
      rpmCache.set(category, rpmMid);
      return rpmMid;
    }
  } catch (_) { }
  rpmCache.set(category, null);
  return null;
}

const projectCache = new Map();
async function getProject(projectId) {
  if (projectCache.has(projectId)) return projectCache.get(projectId);
  try {
    const res = await fetch(`${supabaseUrl}/rest/v1/projects?id=eq.${projectId}&select=id,niche_rpm_category,niche`, { method: 'GET', headers: sbHeaders });
    if (res.ok) {
      const rows = await res.json();
      const proj = rows && rows[0] ? rows[0] : {};
      projectCache.set(projectId, proj);
      return proj;
    }
  } catch (_) { }
  return {};
}

const results = [];
const startDate = data.start_date;
const endDate = data.end_date;
const snapshotMonth = data.snapshot_month;

for (const topic of topics) {
  const topicStart = Date.now();
  const topicResult = {
    topic_id: topic.id,
    project_id: topic.project_id,
    youtube_video_id: topic.youtube_video_id,
    analytics_api_successful: false,
    errors: []
  };

  try {
    // 1. Sum production cost from production_logs, group by stage
    const logsUrl = `${supabaseUrl}/rest/v1/production_logs?topic_id=eq.${topic.id}&select=stage,cost_usd,duration_ms&limit=2000`;
    const logsRes = await fetch(logsUrl, { method: 'GET', headers: sbHeaders });
    let costBreakdown = {};
    let totalCost = 0;
    if (logsRes.ok) {
      const logs = await logsRes.json();
      for (const l of (logs || [])) {
        const stage = l.stage || 'unknown';
        const c = Number(l.cost_usd) || 0;
        costBreakdown[stage] = (costBreakdown[stage] || 0) + c;
        totalCost += c;
      }
      // Round each stage to 3 decimals
      for (const k of Object.keys(costBreakdown)) costBreakdown[k] = Math.round(costBreakdown[k] * 1000) / 1000;
    } else {
      topicResult.errors.push(`production_logs HTTP ${logsRes.status}`);
    }
    totalCost = Math.round(totalCost * 1000) / 1000;
    topicResult.production_cost_usd = totalCost;
    topicResult.cost_breakdown = costBreakdown;

    // 2. Pull YouTube Analytics (aggregate metrics)
    let analyticsRow = null;
    let trafficSourceBreakdown = null;
    let analyticsError = null;

    if (ytOauth && ytChannelId && topic.youtube_video_id) {
      const idsFilter = `channel==${encodeURIComponent(ytChannelId)}`;
      const metricsUrl = `https://youtubeanalytics.googleapis.com/v2/reports?ids=${idsFilter}&metrics=views,estimatedMinutesWatched,averageViewDuration,averageViewPercentage,impressions,impressionClickThroughRate,estimatedRevenue&dimensions=video&filters=video==${topic.youtube_video_id}&startDate=${startDate}&endDate=${endDate}`;
      const aRes = await fetchWithRetry(metricsUrl, {
        method: 'GET',
        headers: { 'Authorization': `Bearer ${ytOauth}` }
      }, 'yt_analytics_metrics');
      if (aRes.ok) {
        const rows = aRes.json?.rows || [];
        const columnHeaders = aRes.json?.columnHeaders || [];
        if (rows.length > 0) {
          const row = rows[0];
          // Map by columnHeader name to be order-robust
          const idx = {};
          columnHeaders.forEach((h, i) => { idx[h.name] = i; });
          analyticsRow = {
            views: Number(row[idx.views] || 0),
            estimated_minutes_watched: Number(row[idx.estimatedMinutesWatched] || 0),
            avg_view_duration_seconds: Number(row[idx.averageViewDuration] || 0),
            avg_view_percentage: Number(row[idx.averageViewPercentage] || 0),
            impressions: Number(row[idx.impressions] || 0),
            ctr: Number(row[idx.impressionClickThroughRate] || 0),
            estimated_revenue_usd: Number(row[idx.estimatedRevenue] || 0)
          };
          topicResult.analytics_api_successful = true;
        } else {
          analyticsError = 'analytics returned 0 rows';
        }
      } else {
        analyticsError = `metrics ${aRes.status || ''}: ${(aRes.error || '').slice(0, 200)}`;
      }

      // 2b. Traffic source dimension
      if (topicResult.analytics_api_successful) {
        const tsUrl = `https://youtubeanalytics.googleapis.com/v2/reports?ids=${idsFilter}&metrics=views&dimensions=insightTrafficSourceType&filters=video==${topic.youtube_video_id}&startDate=${startDate}&endDate=${endDate}`;
        const tsRes = await fetchWithRetry(tsUrl, { method: 'GET', headers: { 'Authorization': `Bearer ${ytOauth}` } }, 'yt_analytics_traffic');
        if (tsRes.ok) {
          const tsRows = tsRes.json?.rows || [];
          const totalTsViews = tsRows.reduce((s, r) => s + (Number(r[1]) || 0), 0);
          const breakdown = { homepage: 0, search: 0, suggested: 0, external: 0, other: 0 };
          for (const r of tsRows) {
            const src = String(r[0] || '').toUpperCase();
            const views = Number(r[1]) || 0;
            const share = totalTsViews > 0 ? views / totalTsViews : 0;
            if (src === 'YT_CHANNEL' || src === 'RELATED_VIDEO' || src === 'YT_OTHER_PAGE') {
              breakdown.suggested = Math.round((breakdown.suggested + share) * 10000) / 10000;
            } else if (src === 'YT_SEARCH') {
              breakdown.search = Math.round((breakdown.search + share) * 10000) / 10000;
            } else if (src === 'EXT_URL') {
              breakdown.external = Math.round((breakdown.external + share) * 10000) / 10000;
            } else if (src === 'YT_HOMEPAGE' || src === 'SUBSCRIBER') {
              breakdown.homepage = Math.round((breakdown.homepage + share) * 10000) / 10000;
            } else {
              breakdown.other = Math.round((breakdown.other + share) * 10000) / 10000;
            }
          }
          trafficSourceBreakdown = breakdown;
        }
        // non-fatal if traffic fails
      }
    } else {
      analyticsError = 'YOUTUBE_OAUTH_TOKEN or YOUTUBE_CHANNEL_ID not set — DB-only mode';
    }

    if (!topicResult.analytics_api_successful) topicResult.errors.push(analyticsError || 'analytics not attempted');

    // 3. Compute derived metrics
    const project = await getProject(topic.project_id);
    const rpmMid = await getRpmMid(project);

    const views30d = analyticsRow ? analyticsRow.views : null;
    const impressions30d = analyticsRow ? analyticsRow.impressions : null;
    const ctr30d = analyticsRow ? analyticsRow.ctr : null;
    const avdSec = analyticsRow ? analyticsRow.avg_view_duration_seconds : null;
    const estimatedRevenue = analyticsRow ? analyticsRow.estimated_revenue_usd : null;

    let actualRpmUsd = null;
    if (views30d && views30d > 0 && estimatedRevenue !== null && estimatedRevenue !== undefined) {
      actualRpmUsd = Math.round((estimatedRevenue / (views30d / 1000)) * 100) / 100;
    }

    let rpmVsBenchmarkPct = null;
    if (actualRpmUsd !== null && rpmMid && rpmMid > 0) {
      rpmVsBenchmarkPct = Math.round((actualRpmUsd / rpmMid) * 100 * 100) / 100;
    }

    let roiPct = null;
    if (totalCost > 0 && estimatedRevenue !== null && estimatedRevenue !== undefined) {
      roiPct = Math.round(((estimatedRevenue - totalCost) / totalCost) * 100 * 100) / 100;
    }

    let breakEvenViews = null;
    if (totalCost > 0 && rpmMid && rpmMid > 0) {
      breakEvenViews = Math.round(totalCost / (rpmMid / 1000));
    }
    const breakEvenAchieved = (views30d !== null && breakEvenViews !== null) ? (views30d >= breakEvenViews) : null;

    // 4. UPSERT revenue_attribution
    const raRow = {
      topic_id: topic.id,
      project_id: topic.project_id,
      snapshot_month: snapshotMonth,
      youtube_video_id: topic.youtube_video_id,
      production_cost_usd: totalCost,
      cost_breakdown: costBreakdown,
      views_30d: views30d,
      impressions_30d: impressions30d,
      ctr_30d: ctr30d,
      avg_view_duration_seconds: avdSec,
      estimated_revenue_usd: estimatedRevenue,
      traffic_source_breakdown: trafficSourceBreakdown,
      actual_rpm_usd: actualRpmUsd,
      rpm_vs_niche_benchmark_pct: rpmVsBenchmarkPct,
      roi_pct: roiPct,
      break_even_achieved: breakEvenAchieved,
      analytics_api_successful: topicResult.analytics_api_successful,
      analytics_error_message: topicResult.analytics_api_successful ? null : (analyticsError || null)
    };

    try {
      const upRes = await fetch(`${supabaseUrl}/rest/v1/revenue_attribution?on_conflict=topic_id,snapshot_month`, {
        method: 'POST',
        headers: { ...sbHeaders, 'Prefer': 'resolution=merge-duplicates,return=minimal' },
        body: JSON.stringify(raRow)
      });
      if (!upRes.ok) topicResult.errors.push(`upsert revenue_attribution HTTP ${upRes.status}`);
    } catch (e) { topicResult.errors.push(`upsert threw: ${e.message}`); }

    // 5. PATCH topics with latest snapshot columns (always — even if analytics failed, we have cost)
    const nowIso = new Date().toISOString();
    const topicPatch = {
      production_cost_usd: totalCost,
      cost_breakdown_snapshot: costBreakdown,
      revenue_attributed_at: nowIso
    };
    if (analyticsRow) {
      topicPatch.estimated_revenue_30d = estimatedRevenue;
      topicPatch.yt_impressions_30d = impressions30d;
      topicPatch.yt_traffic_source_breakdown = trafficSourceBreakdown;
      topicPatch.roi_pct = roiPct;
      topicPatch.break_even_views = breakEvenViews;
      topicPatch.yt_analytics_last_pulled_at = nowIso;
    }
    try {
      const pRes = await fetch(`${supabaseUrl}/rest/v1/topics?id=eq.${topic.id}`, {
        method: 'PATCH',
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify(topicPatch)
      });
      if (!pRes.ok) topicResult.errors.push(`PATCH topic HTTP ${pRes.status}`);
    } catch (e) { topicResult.errors.push(`topic PATCH threw: ${e.message}`); }

    // 6. Backfill pps_calibration actuals
    if (topicResult.analytics_api_successful && analyticsRow) {
      try {
        // Get project median views for implied_actual_score normalization (rough)
        const medRes = await fetch(`${supabaseUrl}/rest/v1/revenue_attribution?project_id=eq.${topic.project_id}&views_30d=not.is.null&select=views_30d&order=views_30d.asc&limit=200`, { method: 'GET', headers: sbHeaders });
        let medianViews = 0;
        if (medRes.ok) {
          const arr = await medRes.json();
          if (arr && arr.length > 0) {
            const vals = arr.map(r => Number(r.views_30d)).filter(n => !isNaN(n));
            medianViews = vals.length > 0 ? vals[Math.floor(vals.length / 2)] : 0;
          }
        }
        // Normalize: score = min(100, (actual / median) * 50) → median = score 50, 2x median = 100
        let impliedActualScore = 50;
        if (medianViews > 0 && views30d !== null) {
          impliedActualScore = Math.round(Math.max(0, Math.min(100, (views30d / medianViews) * 50)));
        } else if (views30d !== null && views30d > 0) {
          // No median yet — anchor to a soft scale
          impliedActualScore = Math.round(Math.max(0, Math.min(100, Math.log10(views30d + 1) * 20)));
        }

        // Fetch calibration rows for this topic awaiting actuals
        const calRes = await fetch(`${supabaseUrl}/rest/v1/pps_calibration?topic_id=eq.${topic.id}&actual_views_30d=is.null&select=id,predicted_pps`, { method: 'GET', headers: sbHeaders });
        if (calRes.ok) {
          const calRows = await calRes.json();
          for (const cr of (calRows || [])) {
            const predicted = Number(cr.predicted_pps) || 0;
            const variance = predicted > 0 ? ((impliedActualScore - predicted) / predicted) : null;
            try {
              await fetch(`${supabaseUrl}/rest/v1/pps_calibration?id=eq.${cr.id}`, {
                method: 'PATCH',
                headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
                body: JSON.stringify({
                  published_at: topic.published_at || null,
                  actual_views_30d: views30d,
                  actual_impressions_30d: impressions30d,
                  actual_ctr: ctr30d,
                  actual_avg_view_duration_seconds: avdSec,
                  actual_revenue_usd: estimatedRevenue,
                  implied_actual_score: impliedActualScore,
                  variance_pct: variance
                })
              });
            } catch (_) { }
          }
          topicResult.calibration_rows_updated = (calRows || []).length;
        }
      } catch (e) {
        topicResult.errors.push(`pps_calibration backfill: ${e.message}`);
      }
    }

    // production_logs per topic
    try {
      await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
        method: 'POST',
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({
          project_id: topic.project_id,
          topic_id: topic.id,
          stage: 'revenue_attribution',
          scene_number: null,
          action: 'monthly_attribute',
          status: topicResult.analytics_api_successful
            ? (topicResult.errors.length === 0 ? 'success' : 'partial')
            : 'analytics_unavailable',
          duration_ms: Date.now() - topicStart,
          cost_usd: 0,
          retry_count: 0
        })
      });
    } catch (_) { }

    topicResult.success = true;
    topicResult.production_cost_usd = totalCost;
    topicResult.estimated_revenue_usd = estimatedRevenue;
    topicResult.roi_pct = roiPct;
    topicResult.break_even_views = breakEvenViews;
    topicResult.break_even_achieved = breakEvenAchieved;
    topicResult.actual_rpm_usd = actualRpmUsd;
  } catch (e) {
    topicResult.success = false;
    topicResult.errors.push(`exception: ${e.message}`);
  }

  results.push(topicResult);
}

return {
  json: {
    batch_index: data.batch_index,
    topics_in_batch: topics.length,
    processed: results.length,
    results,
    snapshot_month: snapshotMonth,
    via_webhook: data.via_webhook
  }
};

// Aggregate across all batches.
const items = $input.all().map(i => i.json);
const meaningful = items.filter(j => !j.skipped);

if (meaningful.length === 0) {
  return [{
    json: {
      success: true,
      topics_processed: 0,
      message: items[0]?.reason || 'No topics needed attribution',
      http_status: 200,
      via_webhook: items[0]?.via_webhook || false
    }
  }];
}

let totalTopics = 0;
let successes = 0;
let analyticsOk = 0;
let analyticsFail = 0;
let totalCost = 0;
let totalRevenue = 0;
let breakEvenCount = 0;
let breakEvenMeasured = 0;
let calibrationUpdated = 0;
const failures = [];

for (const m of meaningful) {
  for (const r of (m.results || [])) {
    totalTopics += 1;
    if (r.success) successes += 1;
    else failures.push({ topic_id: r.topic_id, errors: r.errors });
    if (r.analytics_api_successful) analyticsOk += 1; else analyticsFail += 1;
    if (typeof r.production_cost_usd === 'number') totalCost += r.production_cost_usd;
    if (typeof r.estimated_revenue_usd === 'number') totalRevenue += r.estimated_revenue_usd;
    if (r.break_even_achieved === true) breakEvenCount += 1;
    if (r.break_even_achieved !== null && r.break_even_achieved !== undefined) breakEvenMeasured += 1;
    if (r.calibration_rows_updated) calibrationUpdated += r.calibration_rows_updated;
  }
}

const netMargin = totalCost > 0 ? Math.round(((totalRevenue - totalCost) / totalCost) * 100 * 100) / 100 : null;

return [{
  json: {
    success: true,
    snapshot_month: meaningful[0]?.snapshot_month || null,
    topics_processed: totalTopics,
    successes,
    failures_count: failures.length,
    analytics_ok: analyticsOk,
    analytics_failed: analyticsFail,
    total_cost_usd: Math.round(totalCost * 1000) / 1000,
    total_estimated_revenue_usd: Math.round(totalRevenue * 100) / 100,
    portfolio_roi_pct: netMargin,
    break_even_rate: breakEvenMeasured > 0 ? Math.round((breakEvenCount / breakEvenMeasured) * 10000) / 100 : null,
    calibration_rows_backfilled: calibrationUpdated,
    failures: failures.slice(0, 20),
    finished_at: new Date().toISOString(),
    http_status: 200,
    via_webhook: meaningful.some(m => m.via_webhook)
  }
}];
